#!/bin/bash\n\n# ZLAPS Desktop Application Launcher\n# This script sets up and launches the ZLAPS desktop GUI on your computer\n\necho \"================================\"\necho \"🌊 ZLAPS Desktop Application 🌊\"\necho \"================================\"\necho \"\"\n\n# Check if Python is installed\nif ! command -v python3 &> /dev/null; then\n    echo \"❌ Error: Python 3 is not installed\"\n    echo \"Please install Python 3.7 or higher from https://www.python.org/\"\n    exit 1\nfi\n\necho \"✓ Python 3 found\"\npython3 --version\necho \"\"\n\n# Check if we're in the zlaps directory\nif [ ! -f \"communication_core.py\" ]; then\n    echo \"❌ Error: Not in zlaps directory\"\n    echo \"Please run this script from the zlaps folder:\"\n    echo \"  cd zlaps\"\n    echo \"  bash launch_desktop.sh\"\n    exit 1\nfi\n\necho \"✓ ZLAPS directory detected\"\necho \"\"\n\n# Install/upgrade pip\necho \"📦 Checking dependencies...\"\npython3 -m pip install --upgrade pip --quiet\n\n# Install required packages\necho \"📦 Installing required packages...\"\npython3 -m pip install -r requirements.txt --quiet\npython3 -m pip install pillow --quiet\n\necho \"✓ Dependencies installed\"\necho \"\"\n\n# Generate logo if it doesn't exist\nif [ ! -f \"zlaps_logo.png\" ]; then\n    echo \"🎨 Generating logo...\"\n    python3 generate_logo.py\n    echo \"\"\nfi\n\n# Launch the desktop app\necho \"🚀 Launching ZLAPS Desktop Application...\"\necho \"✓ Opening window on your desktop...\"\necho \"\"\npython3 zlaps_desktop.py\n\necho \"\"\necho \"❌ Application closed\"\n
